1	# GitButler as one package. The Tauri GUI binary is multi-call (`builtin-but`),
2	# so it also acts as the `but` CLI/TUI when invoked by that name. We add the
3	# `but` and `gitbutler` symlinks to it — upstream's Linux .deb does the same
4	# `but -> gitbutler-tauri` symlink; nixpkgs ships only `gitbutler-tauri`.
5	# To bump: set `version`, then refresh the src/cargoDeps/pnpmDeps hashes from
6	# the hash-mismatch errors on rebuild.
7	# Upstream tags: https://github.com/gitbutlerapp/gitbutler/tags
8	final: _prev: let
9	  version = "0.21.0";
10	  src = final.unstable.fetchFromGitHub {
11	    owner = "gitbutlerapp";
12	    repo = "gitbutler";
13	    tag = "release/${version}";
14	    hash = "REDACTED/8Ec/q3NDUs=";
15	  };
16	  cargoDeps = final.unstable.rustPlatform.fetchCargoVendor {
17	    inherit src;
18	    name = "gitbutler-${version}-vendor";
19	    hash = "REDACTED/zODzLOMAridd7ImAEc8=";
20	  };
21	in {
22	  gitbutler = final.unstable.gitbutler.overrideAttrs (_finalAttrs: prev: {
23	    inherit version src cargoDeps;
24	
25	    # prev.pnpmDeps already tracks the new src/version via finalAttrs;
26	    # only its fixed-output hash needs refreshing.
27	    pnpmDeps = prev.pnpmDeps.overrideAttrs {
28	      outputHash = "REDACTED";
29	    };
30	
31	    # The `but` integration tests build git fixtures by running scripts at
32	    # check time; the Nix sandbox has no git for that.
33	    doCheck = false;
34	
35	    # nixpkgs' 0.19.9 postPatch lists `gitbutler-git-setsid` in externalBin, but
36	    # upstream dropped that binary; Linux release builds ship askpass only and
37	    # enable `builtin-but` (scripts/release.sh in the gitbutler repo).
38	    postPatch = ''
39	      tauriConfRelease="crates/gitbutler-tauri/tauri.conf.release.json"
40	      jq '.
41	          | (.version = "${version}")
42	          | (.bundle.createUpdaterArtifacts = false)
43	          | (.bundle.externalBin = ["gitbutler-git-askpass"])
44	        ' "$tauriConfRelease" | sponge "$tauriConfRelease"
45	
46	      substituteInPlace apps/desktop/src/lib/backend/tauri.ts \
47	        --replace-fail 'checkUpdate = tauriCheck;' 'checkUpdate = () => null;'
48	    '';
49	
50	    # `builtin-but` makes the one binary act as `but` when invoked by that name.
51	    tauriBuildFlags = prev.tauriBuildFlags ++ [
52	      "--features"
53	      "builtin-but,packaged-but-distribution"
54	    ];
55	
56	    # `but` = CLI/TUI (with `but tui` / `but gui` subcommands); `gitbutler` = GUI.
57	    # Both symlink the one multi-call binary, like upstream's .deb `but` symlink.
58	    postInstall = (prev.postInstall or "") + ''
59	      ln -sf gitbutler-tauri $out/bin/but
60	      ln -sf gitbutler-tauri $out/bin/gitbutler
61	    '';
62	  });
63	}
